#!/bin/zsh
set -euo pipefail
# --- config --- FAIL_MSG="FAILED" MAGICK="/opt/homebrew/bin/magick" CANVAS_SIZE=256 BORDER=30 INNER_SIZE=$((CANVAS_SIZE - BORDER * 2)) RADIUS=60 # rounded corner radius
# --- logging function (stderr) --- log() { echo "[LOG] $1" >&2 }
# --- error handler --- fail() { echo "$FAIL_MSG" exit 1 }
# --- input check --- if [[ $# -ne 1 ]]; then log "Invalid number of arguments" fail fi
INPUT_PATH="$1"
log "Received input: $INPUT_PATH"
if [[ ! -f "$INPUT_PATH" ]]; then log "Input file does not exist" fail fi
# --- prepare paths --- DIR=$(dirname "$INPUT_PATH") FILENAME=$(basename "$INPUT_PATH") NAME="${FILENAME%.*}" EXT="${FILENAME##*.}"
OUTPUT_PATH="$DIR/${NAME}_256.png"
log "Output will be: $OUTPUT_PATH"
# --- temp files --- TMP_IMG=$(mktemp -t imgXXXXXX).png TMP_MASK=$(mktemp -t maskXXXXXX).png
log "Temporary image: $TMP_IMG" log "Temporary mask: $TMP_MASK"
cleanup() { [[ -n "$TMP_IMG" && -f "$TMP_IMG" ]] && rm -f "$TMP_IMG" [[ -n "$TMP_MASK" && -f "$TMP_MASK" ]] && rm -f "$TMP_MASK" }
trap cleanup EXIT
# --- resize image to fit inner box --- log "Resizing image to fit ${INNER_SIZE}x${INNER_SIZE}" "$MAGICK" "$INPUT_PATH" \ -resize "${INNER_SIZE}x${INNER_SIZE}" \ "$TMP_IMG" || { log "Resize failed"; fail; }
# --- create Apple-style squircle mask --- log "Creating Apple-style squircle mask"
"$MAGICK" -size "${INNER_SIZE}x${INNER_SIZE}" xc:black \ -channel RGB \ -fx 'pow(abs(2*i/w-1),5)+pow(abs(2*j/h-1),5)<=1 ? 1 : 0' \ -blur 0x0.5 \ "$TMP_MASK" || { log "Mask creation failed"; fail; }
# --- apply rounded corners --- log "Applying rounded corners"
"$MAGICK" "$TMP_IMG" \ -alpha set \ "$TMP_MASK" \ -compose CopyOpacity -composite \ "$TMP_IMG" || { log "Rounded corner apply failed"; fail; }
# --- place onto canvas --- log "Compositing onto ${CANVAS_SIZE}x${CANVAS_SIZE} canvas" "$MAGICK" -size "${CANVAS_SIZE}x${CANVAS_SIZE}" xc:none \ "$TMP_IMG" \ -gravity center -composite \ "$OUTPUT_PATH" || { log "Final composite failed"; fail; }
# --- success --- log "Image created successfully"
echo "$OUTPUT_PATH" exit 0

#!/bin/zsh
set -euo pipefail
# --- config --- FAIL_MSG="FAILED" MAGICK="/opt/homebrew/bin/magick" CANVAS_SIZE=256 BORDER=30 INNER_SIZE=$((CANVAS_SIZE - BORDER * 2)) RADIUS=60 # rounded corner radius
# --- logging function (stderr) --- log() { echo "[LOG] $1" >&2 }
# --- error handler --- fail() { echo "$FAIL_MSG" exit 1 }
# --- input check --- if [[ $# -ne 1 ]]; then log "Invalid number of arguments" fail fi
INPUT_PATH="$1"
log "Received input: $INPUT_PATH"
if [[ ! -f "$INPUT_PATH" ]]; then log "Input file does not exist" fail fi
# --- prepare paths --- DIR=$(dirname "$INPUT_PATH") FILENAME=$(basename "$INPUT_PATH") NAME="${FILENAME%.*}" EXT="${FILENAME##*.}"
OUTPUT_PATH="$DIR/${NAME}_256.png"
log "Output will be: $OUTPUT_PATH"
# --- temp files --- TMP_IMG=$(mktemp /tmp/imgXXXX.png) TMP_MASK=$(mktemp /tmp/maskXXXX.png)
log "Temporary image: $TMP_IMG" log "Temporary mask: $TMP_MASK"
# --- resize image to fit inner box --- log "Resizing image to fit ${INNER_SIZE}x${INNER_SIZE}" "$MAGICK" "$INPUT_PATH" \ -resize "${INNER_SIZE}x${INNER_SIZE}" \ "$TMP_IMG" || { log "Resize failed"; fail; }
# --- create rounded mask --- log "Creating rounded corner mask"
"$MAGICK" -size "${INNER_SIZE}x${INNER_SIZE}" xc:black \ -fill white \ -draw "roundrectangle 0,0 $INNER_SIZE,$INNER_SIZE $RADIUS,$RADIUS" \ "$TMP_MASK" || { log "Mask creation failed"; fail; }
# --- apply rounded corners --- log "Applying rounded corners"
"$MAGICK" "$TMP_IMG" \ -alpha set \ "$TMP_MASK" \ -compose CopyOpacity -composite \ "$TMP_IMG" || { log "Rounded corner apply failed"; fail; }
# --- place onto canvas --- log "Compositing onto ${CANVAS_SIZE}x${CANVAS_SIZE} canvas" "$MAGICK" -size "${CANVAS_SIZE}x${CANVAS_SIZE}" xc:none \ "$TMP_IMG" \ -gravity center -composite \ "$OUTPUT_PATH" || { log "Final composite failed"; fail; }
# --- cleanup --- log "Cleaning up temp files" rm -f "$TMP_IMG" "$TMP_MASK" || { log "Cleanup failed"; fail; }
# --- success --- log "Image created successfully"
echo "$OUTPUT_PATH" exit 0
